  APP_HEADER_BAR,
  APP_HEADER_ROW_PANEL,
  APP_HEADER_TITLE,
} from "@/components/appHeaderLayout";
import { JiraTicketLink } from "@/components/JiraTicketLink";
import {
  ArrowLeft,
  Loader2,
  CheckCircle2,
  Circle,
