                <div className="flex items-center gap-2 mb-0.5">
                  <Badge variant="outline" className="text-xs">{e.type}</Badge>
                  <span className="text-sm font-medium">{e.title}</span>
                </div>
                <p className="text-sm text-muted-foreground line-clamp-2">{e.body}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Checkpoint footer (approval gate + follow-up chat) ───────────────────────

const NEXT_STAGE_LABEL: Partial<Record<Stage, string>> = {
  grooming: "Proceed to Impact Analysis",
  impact: "Proceed to Triage",
  plan: "Proceed to Implementation Guidance",
  guidance: "Proceed to Test Suggestions",
  tests: "Proceed to Code Review",
  review: "Proceed to PR Description",
  pr: "Proceed to Retrospective",
  retro: "Mark Pipeline Complete",
};

interface CheckpointFooterProps {
  stage: Stage;
  onProceed: () => void;
  proceeding: boolean;
  hasBlockingIssues?: boolean;
  chat: TriageMessage[];
  input: string;
  onInputChange: (v: string) => void;
  onSend: () => void;
  sending: boolean;
  // grooming stage only
  groomingChatLabel?: string;
}

function CheckpointFooter({
  stage, onProceed, proceeding, hasBlockingIssues,
  chat, input, onInputChange, onSend, sending,
  groomingChatLabel,
}: CheckpointFooterProps) {
  const [chatOpen, setChatOpen] = useState(stage === "grooming"); // auto-open for grooming
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatOpen) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat, chatOpen]);

  const nextLabel = NEXT_STAGE_LABEL[stage] ?? "Proceed";
  const chatToggleLabel = groomingChatLabel ?? "Ask a follow-up question";

  return (
    <div className="mt-5 border-t pt-4 space-y-3">
      {/* Collapsible conversation */}
      <div>
        <button
          onClick={() => setChatOpen(!chatOpen)}
          className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors"
        >
          <ChevronRight className={`h-3.5 w-3.5 transition-transform ${chatOpen ? "rotate-90" : ""}`} />
          {chatToggleLabel}
          {chat.length > 0 && (
            <span className="ml-1 px-1.5 py-0.5 rounded-full bg-muted text-xs font-medium">
              {Math.ceil(chat.length / 2)}
            </span>
          )}
        </button>

        {chatOpen && (
          <div className="mt-2 space-y-2">
            {chat.length > 0 && (
              <div className="space-y-2 max-h-64 overflow-y-auto pr-1">
                {chat.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                    <div className={`max-w-[85%] rounded-lg px-3 py-2 text-sm leading-relaxed ${
                      msg.role === "user" ? "bg-primary text-primary-foreground" : "bg-muted text-foreground"
                    }`}>
                      <p className="whitespace-pre-wrap">{msg.content}</p>
                    </div>
                  </div>
                ))}
                {sending && (
                  <div className="flex justify-start">
                    <div className="bg-muted rounded-lg px-3 py-2 flex items-center gap-2 text-sm text-muted-foreground">
                      <Loader2 className="h-3.5 w-3.5 animate-spin" /> Thinking…
                    </div>
                  </div>
                )}
                <div ref={bottomRef} />
              </div>
            )}
            <div className="flex gap-2">
              <Textarea
                value={input}
                onChange={(e) => onInputChange(e.target.value)}
                placeholder={stage === "grooming"
                  ? "Suggest changes to the ticket, acceptance criteria, or scope…"
                  : "Ask about these findings…"}
                className="min-h-[52px] resize-none text-sm"
                onKeyDown={(e) => {
                  if (e.key === "Enter" && (e.metaKey || e.ctrlKey) && input.trim()) {
                    e.preventDefault();
                    onSend();
                  }
                }}
                disabled={sending || proceeding}
              />
              <Button size="icon" onClick={onSend} disabled={!input.trim() || sending || proceeding} title="Send (⌘↵)">
                <Send className="h-4 w-4" />
              </Button>
            </div>
            <p className="text-xs text-muted-foreground">⌘↵ to send</p>
          </div>
        )}
      </div>

      {/* Approval button row */}
      <div className="flex items-center justify-between gap-3">
        {hasBlockingIssues && (
          <p className="text-xs text-amber-600 dark:text-amber-400 flex items-center gap-1.5">
            <AlertTriangle className="h-3.5 w-3.5 shrink-0" />
            Blocking issues present — proceeding not recommended
          </p>
        )}
        <Button
          onClick={onProceed}
          disabled={proceeding}
          variant={hasBlockingIssues ? "outline" : "default"}
          className="gap-2 ml-auto"
        >
          {proceeding ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <ChevronRight className="h-4 w-4" />
          )}
          {hasBlockingIssues ? `Proceed anyway: ${nextLabel}` : nextLabel}
        </Button>
      </div>
    </div>
  );
}

// ── Triage chat UI ────────────────────────────────────────────────────────────

interface TriageChatProps {
  history: TriageMessage[];
  input: string;
  onInputChange: (v: string) => void;
  onSend: () => void;
  onFinalize: () => void;
  sending: boolean;
  finalizing: boolean;
}

function TriageChat({ history, input, onInputChange, onSend, onFinalize, sending, finalizing }: TriageChatProps) {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [history]);

  return (
    <div className="flex flex-col gap-3">
      <div className="space-y-3 pr-1">
        {history.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
            <div className={`max-w-[85%] rounded-lg px-3 py-2.5 text-sm leading-relaxed ${
              msg.role === "user"
                ? "bg-primary text-primary-foreground"
                : "bg-muted text-foreground"
            }`}>
              <p className="whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {sending && (
          <div className="flex justify-start">
            <div className="bg-muted rounded-lg px-3 py-2.5 flex items-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="h-3.5 w-3.5 animate-spin" /> Thinking…
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <div className="flex gap-2">
        <Textarea
          value={input}
          onChange={(e) => onInputChange(e.target.value)}
          placeholder="Respond to the agent's questions or provide clarification…"
          className="min-h-[60px] resize-none text-sm"
          onKeyDown={(e) => {
            if (e.key === "Enter" && (e.metaKey || e.ctrlKey) && input.trim()) {
              e.preventDefault();
              onSend();
            }
          }}
          disabled={sending || finalizing}
        />
        <div className="flex flex-col gap-2">
          <Button
            size="icon"
            onClick={onSend}
            disabled={!input.trim() || sending || finalizing}
            title="Send (⌘↵)"
          >
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </div>

      <div className="mt-2 flex items-center justify-between">
        <p className="text-xs text-muted-foreground">⌘↵ to send</p>
        <Button
          onClick={onFinalize}
          disabled={sending || finalizing || history.length === 0}
          className="gap-2"
        >
          {finalizing ? (
            <><Loader2 className="h-4 w-4 animate-spin" /> Finalising plan…</>
          ) : (
            <><CheckCircle2 className="h-4 w-4" /> Finalise Plan →</>
          )}
        </Button>
      </div>
    </div>
  );
}

// ── Ticket selector ───────────────────────────────────────────────────────────

interface TicketSelectorProps {
  sprintIssues: JiraIssue[];
  loading: boolean;
  onSelect: (issue: JiraIssue) => void;
}

function TicketSelector({ sprintIssues, loading, onSelect }: TicketSelectorProps) {
  const [search, setSearch] = useState("");
  const [searchResults, setSearchResults] = useState<JiraIssue[]>([]);
  const [searching, setSearching] = useState(false);
  const q = search.trim();

  useEffect(() => {
    if (!q) { setSearchResults([]); return; }
    const isKey = /^[A-Z]+-\d+$/i.test(q);
    const jql = isKey ? `key = "${q.toUpperCase()}"` : `text ~ "${q}" ORDER BY updated DESC`;
    const timer = setTimeout(async () => {
      setSearching(true);
      try { setSearchResults(await searchJiraIssues(jql, 20)); }
      catch { setSearchResults([]); }
      finally { setSearching(false); }
    }, 500);
    return () => clearTimeout(timer);
  }, [q]);

  const list = q ? searchResults : sprintIssues;
  const busy = q ? searching : loading;

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      <div>
        <h2 className="text-base font-semibold mb-3">Select a Ticket to Implement</h2>
        <div className="relative">
          <Input
            placeholder="Search by text or key (e.g. PROJ-123)…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-4"
          />
        </div>
      </div>

      {busy ? (
        <div className="flex items-center justify-center py-12 text-muted-foreground gap-2 text-sm">
          <Loader2 className="h-4 w-4 animate-spin" /> {q ? "Searching…" : "Loading sprint tickets…"}
        </div>
      ) : list.length === 0 ? (
        <p className="text-sm text-muted-foreground text-center py-12">
          {q ? "No tickets found." : "No active sprint tickets assigned to you."}
        </p>
      ) : (
        <div className="space-y-2">
          {!q && <p className="text-xs text-muted-foreground">Active sprint — {list.length} ticket{list.length !== 1 ? "s" : ""} assigned to you</p>}
          {list.map((issue) => (
            <button
              key={issue.id}
              onClick={() => onSelect(issue)}
              className="w-full text-left px-4 py-3 rounded-md border bg-card/60 hover:bg-muted/60 transition-colors"
            >
              <div className="flex items-center gap-2 mb-1">
                <JiraTicketLink ticketKey={issue.key} url={issue.url} />
                <Badge variant="outline" className="text-xs">{issue.issueType}</Badge>
                {issue.storyPoints != null && (
                  <span className="ml-auto text-xs text-muted-foreground">{issue.storyPoints}pt</span>
                )}
              </div>
              <p className="text-sm font-medium leading-snug">{issue.summary}</p>
              <p className="text-xs text-muted-foreground mt-0.5">{issue.status}</p>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Pipeline sidebar ──────────────────────────────────────────────────────────

interface PipelineSidebarProps {
  currentStage: Stage;
  completedStages: Set<Stage>;
  activeStage: Stage;
  pendingApproval: Stage | null;
  onClickStage: (stage: Stage) => void;
}

function PipelineSidebar({ currentStage, completedStages, activeStage, pendingApproval, onClickStage }: PipelineSidebarProps) {
  const icons: Record<string, React.ReactNode> = {
    grooming: <BookOpen className="h-3.5 w-3.5" />,
    impact: <Shield className="h-3.5 w-3.5" />,
    triage: <ClipboardList className="h-3.5 w-3.5" />,
    plan: <ClipboardList className="h-3.5 w-3.5" />,
    guidance: <FileCode className="h-3.5 w-3.5" />,
    tests: <TestTube className="h-3.5 w-3.5" />,
    review: <Shield className="h-3.5 w-3.5" />,
    pr: <GitPullRequest className="h-3.5 w-3.5" />,
    retro: <BookOpen className="h-3.5 w-3.5" />,
  };

  return (
    <div className="min-h-0 w-48 shrink-0 overflow-y-auto border-r bg-muted/20 p-3 space-y-1">
      {STAGE_ORDER.map((stage) => {
        const done = completedStages.has(stage);
        const active = activeStage === stage;
        const running = currentStage === stage && !done && pendingApproval !== stage;
        const pending = pendingApproval === stage;
        const reachable = done || active || running || pending;
        return (
          <button
            key={stage}
            onClick={() => reachable && onClickStage(stage)}
            disabled={!reachable}
            className={`w-full flex items-center gap-2 px-2.5 py-2 rounded-md text-left text-xs transition-colors ${
              active
                ? "bg-primary text-primary-foreground font-medium"
                : pending
                ? "bg-amber-50 dark:bg-amber-950/30 text-amber-700 dark:text-amber-300 font-medium hover:bg-amber-100 dark:hover:bg-amber-950/50 cursor-pointer"
                : done
                ? "text-foreground hover:bg-muted/60 cursor-pointer"
                : "text-muted-foreground cursor-default opacity-50"
            }`}
          >
            {running ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin shrink-0" />
            ) : pending ? (
              <AlertTriangle className="h-3.5 w-3.5 text-amber-500 shrink-0" />
            ) : done ? (
              <CheckCircle2 className="h-3.5 w-3.5 text-green-500 shrink-0" />
            ) : (
              <span className="shrink-0 opacity-60">{icons[stage] ?? <Circle className="h-3.5 w-3.5" />}</span>
            )}
            <span>{STAGE_LABELS[stage]}</span>
          </button>
        );
      })}
    </div>
  );
}

// ── Stage → pipeline step mapping ────────────────────────────────────────────

function stageToStep(stage: Stage): number | undefined {
  if (stage === "select") return undefined;
  const map: Record<Exclude<Stage, "select">, number> = {
    grooming:  0,
    impact:    1,
    triage:    2,
    plan:      2,
    guidance:  3,
    tests:     4,
    review:    5,
    pr:        6,
    retro:     7,
    complete:  7,
  };
  return map[stage];
}

// ── Main screen ───────────────────────────────────────────────────────────────

export function ImplementTicketScreen({ credStatus, onBack }: ImplementTicketScreenProps) {
  const claudeAvailable = aiProviderComplete(credStatus);
  const jiraAvailable = jiraComplete(credStatus);

  // Ticket selection
  const [sprintIssues, setSprintIssues] = useState<JiraIssue[]>([]);
  const [loadingIssues, setLoadingIssues] = useState(true);
  const [selectedIssue, setSelectedIssue] = useState<JiraIssue | null>(null);

  // Pipeline state
  const [currentStage, setCurrentStage] = useState<Stage>("select");
  const [viewingStage, setViewingStage] = useState<Stage>("grooming");
  const [completedStages, setCompletedStages] = useState<Set<Stage>>(new Set());

  // Agent outputs
  const [grooming, setGrooming] = useState<GroomingOutput | null>(null);
  const [impact, setImpact] = useState<ImpactOutput | null>(null);
  const [triageHistory, setTriageHistory] = useState<TriageMessage[]>([]);
  const [triageInput, setTriageInput] = useState("");
  const [triageSending, setTriageSending] = useState(false);
  const [triaFinalizing, setTriaFinalizing] = useState(false);
  const [plan, setPlan] = useState<ImplementationPlan | null>(null);
  const [guidance, setGuidance] = useState<GuidanceOutput | null>(null);
  const [tests, setTests] = useState<TestOutput | null>(null);
  const [review, setReview] = useState<PlanReviewOutput | null>(null);
  const [prDescription, setPrDescription] = useState<PrDescriptionOutput | null>(null);
  const [retrospective, setRetrospective] = useState<RetrospectiveOutput | null>(null);
  const [kbSaved, setKbSaved] = useState(false);

  // Per-stage error
  const [errors, setErrors] = useState<Partial<Record<Stage, string>>>({});

  // Approval gate — which stage is waiting for user approval before advancing
  const [pendingApproval, setPendingApproval] = useState<Stage | null>(null);
  const [proceeding, setProceeding] = useState(false);

  // Grooming blockers
  const [groomingBlockers, setGroomingBlockers] = useState<GroomingBlocker[]>([]);

  // Checkpoint conversations (follow-up chat at each stage's approval gate)
  const [checkpointChats, setCheckpointChats] = useState<Partial<Record<Stage, TriageMessage[]>>>({});
  const [checkpointInput, setCheckpointInput] = useState("");
  const [checkpointSending, setCheckpointSending] = useState(false);

  // Grooming conversation state (separate from generic checkpoint chat)
  const [groomingChat, setGroomingChat] = useState<TriageMessage[]>([]);
  const [groomingChatInput, setGroomingChatInput] = useState("");
  const [groomingChatSending, setGroomingChatSending] = useState(false);
  const [groomingBaseline, setGroomingBaseline] = useState<GroomingOutput | null>(null);
  const [jiraUpdateStatus, setJiraUpdateStatus] = useState<"idle" | "saving" | "saved" | "error">("idle");
  const [jiraUpdateError, setJiraUpdateError] = useState("");

  // Resizable grooming split pane — right panel width in px (null = default 320)
  const [chatPaneWidth, setChatPaneWidth] = useState<number>(320);
  const isDraggingRef = useRef(false);
  const dragStartXRef = useRef(0);
  const dragStartWidthRef = useRef(0);

  const onDividerMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    isDraggingRef.current = true;
    dragStartXRef.current = e.clientX;
    dragStartWidthRef.current = chatPaneWidth;

    const onMouseMove = (ev: MouseEvent) => {
      if (!isDraggingRef.current) return;
      // Dragging left increases the chat pane width; right decreases it.
      const delta = dragStartXRef.current - ev.clientX;
      const next = Math.min(600, Math.max(240, dragStartWidthRef.current + delta));
      setChatPaneWidth(next);
    };
    const onMouseUp = () => {
      isDraggingRef.current = false;
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    };
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }, [chatPaneWidth]);

  // Refs for pipeline data — avoids stale closures in async stage functions
  const groomingRef = useRef<GroomingOutput | null>(null);
  const impactRef = useRef<ImpactOutput | null>(null);
  const planRef = useRef<ImplementationPlan | null>(null);
  const guidanceRef = useRef<GuidanceOutput | null>(null);
  const testsRef = useRef<TestOutput | null>(null);
  const reviewRef = useRef<PlanReviewOutput | null>(null);
  const ticketTextRef = useRef<string>("");
  const worktreeRef = useRef<WorktreeInfo | null>(null);

  /** Fade in header meridian (PipelineProgress) over 1s when this screen mounts. */
  const [meridianHeaderVisible, setMeridianHeaderVisible] = useState(false);

  const ticketText = selectedIssue ? compileTicketText(selectedIssue) : "";
  // Keep ref in sync with the current ticket text
  ticketTextRef.current = ticketText;

  function markComplete(stage: Stage) {
    setCompletedStages((prev) => new Set([...prev, stage]));
  }

  function setError(stage: Stage, err: string) {
    setErrors((prev) => ({ ...prev, [stage]: err }));
  }

  // Load sprint issues assigned to the current user
  useEffect(() => {
    if (!jiraAvailable) { setLoadingIssues(false); return; }
    getMySprintIssues().then(setSprintIssues).catch(() => {}).finally(() => setLoadingIssues(false));
  }, [jiraAvailable]);

  useEffect(() => {
    const t = window.setTimeout(() => setMeridianHeaderVisible(true), 0);
    return () => clearTimeout(t);
  }, []);

  // Stable ref for skills — loaded once at pipeline start, used throughout
  const skillsRef = useRef<Partial<Record<SkillType, string>>>({});

  // Start pipeline — runs Grooming only, then waits for user approval
  const startPipeline = useCallback(async (issue: JiraIssue) => {
    setSelectedIssue(issue);
    setCurrentStage("grooming");
    setViewingStage("grooming");
    setCompletedStages(new Set());
    setPendingApproval(null);
    setGroomingBlockers([]);
    setCheckpointChats({});
    setCheckpointInput("");
    setGrooming(null); setImpact(null); setPlan(null);
    setGuidance(null); setTests(null); setReview(null);
    setPrDescription(null); setRetrospective(null);
    setTriageHistory([]); setTriageInput(""); setErrors({});
    groomingRef.current = null; impactRef.current = null;
    planRef.current = null; guidanceRef.current = null;
    testsRef.current = null; reviewRef.current = null;
    setGroomingChat([]);
    setGroomingChatInput("");
    setGroomingChatSending(false);
    setGroomingBaseline(null);
    setJiraUpdateStatus("idle");
    setJiraUpdateError("");

    // Fetch the full issue with ?expand=names so all custom fields (Steps to Reproduce,
    // Observed/Expected Behavior, Acceptance Criteria, named_fields, etc.) are populated.
    // The sprint list fetch only returns BASE_FIELDS with no names expansion.
    let fullIssue = issue;
    try {
      fullIssue = await getIssue(issue.key);
      setSelectedIssue(fullIssue);
    } catch {
      // Fall back to the sprint-list version if the detailed fetch fails
    }

    const text = compileTicketText(fullIssue);
    ticketTextRef.current = text;

    try {
      skillsRef.current = await loadAgentSkills();
    } catch { skillsRef.current = {}; }

    // Sync the worktree to the latest base branch state (best-effort — pipeline
    // continues even if the worktree isn't configured or the fetch fails).
    let repoContext = "";
    try {
      const config = await getNonSecretConfig();
      const worktreePath = config["repo_worktree_path"];
      if (worktreePath) {
        const info = await syncWorktree();
        worktreeRef.current = info;
        repoContext = `\n\n=== CODEBASE CONTEXT ===\nWorktree: ${info.path}\nBranch: ${info.branch} (HEAD: ${info.headCommit})\nCommit: ${info.headMessage}\nYou have access to this codebase via glob_repo_files, grep_repo_files, and read_repo_file tools. Use them to find relevant files — do NOT guess file contents.`;
      }
    } catch (e) {
      // Worktree sync failure is non-fatal — log it but don't block the pipeline
      console.warn("[Meridian] Worktree sync failed:", e);
    }

    // Agent 1: Grooming
    try {
      const groomingInput = prependSkill(text + repoContext, skillsRef.current.grooming, "GROOMING CONVENTIONS");
      const raw = await runGroomingAgent(groomingInput);
      const data = parseAgentJson<GroomingOutput>(raw);
      if (!data) throw new Error("Could not parse grooming output");
      groomingRef.current = data;
      setGrooming(data);
      markComplete("grooming");
      // Detect blockers before presenting to user
      setGroomingBlockers(detectGroomingBlockers(fullIssue, data));
      // ── CHECKPOINT: wait for user approval ──
      setPendingApproval("grooming");
    } catch (e) {
      setError("grooming", String(e));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Grooming conversation ─────────────────────────────────────────────────────

  async function sendGroomingChatMessage() {
    const msg = groomingChatInput.trim();
    if (!msg || !groomingRef.current) return;
    setGroomingChatInput("");

    // Snapshot the grooming output before the very first refinement turn so we
    // can diff against it and highlight changes in the panel above the chat.
    if (groomingChat.length === 0 && groomingBaseline === null) {
      setGroomingBaseline(groomingRef.current);
    }

    const userMsg: TriageMessage = { role: "user", content: msg };
    const newHistory = [...groomingChat, userMsg];
    setGroomingChat(newHistory);
    setGroomingChatSending(true);

    // Build a grooming-specific system context so the agent knows its role here
    const systemContext = [
      "=== GROOMING CONVERSATION INSTRUCTIONS ===",
      "You are a grooming agent helping refine a JIRA ticket. The user may suggest changes to:",
      "- The ticket's acceptance criteria",
      "- The relevant areas / files",
      "- Ambiguities or dependencies",
      "- The overall ticket summary or scope",
      "",
      "When the user proposes a change, acknowledge what you are updating and explain your reasoning.",
      "After agreeing on any changes, output ONLY a JSON block (fenced with ```json ... ```) containing",
      "the complete updated grooming output in this exact schema:",
      JSON.stringify({
        ticket_summary: "<string>",
        ticket_type: "<feature|bug|chore|spike>",
        acceptance_criteria: ["<string>"],
        relevant_areas: [{ area: "<string>", reason: "<string>", files_to_check: ["<string>"] }],
        ambiguities: ["<string>"],
        dependencies: ["<string>"],
        estimated_complexity: "<low|medium|high>",
        grooming_notes: "<string>",
      }, null, 2),
      "",
      "If no changes are being agreed upon in this turn (e.g. just a question), respond in plain text and OMIT the JSON block.",
      "=== TICKET ===",
      ticketTextRef.current,
      "=== CURRENT GROOMING ANALYSIS ===",
      JSON.stringify(groomingRef.current, null, 2),
    ].join("\n");

    try {
      const response = await runGroomingChatTurn(systemContext, JSON.stringify(newHistory));
      const withAssistant: TriageMessage[] = [...newHistory, { role: "assistant" as const, content: response }];
      setGroomingChat(withAssistant);

      // Parse any updated grooming JSON out of the response
      const jsonMatch = response.match(/```json\s*([\s\S]*?)```/);
      if (jsonMatch) {
        const updated = parseAgentJson<GroomingOutput>(jsonMatch[1]);
        if (updated) {
          groomingRef.current = updated;
          setGrooming(updated);
          // Re-detect blockers with updated output
          if (selectedIssue) setGroomingBlockers(detectGroomingBlockers(selectedIssue, updated));
        }
      }
    } catch { /* silently handle */ }
    finally { setGroomingChatSending(false); }
  }

  async function pushGroomingToJira() {
    if (!selectedIssue || !groomingRef.current) return;
    setJiraUpdateStatus("saving");
    setJiraUpdateError("");
    try {
      // Build a plain-text description from the current grooming output
      const g = groomingRef.current;
      const lines: string[] = [];
      lines.push(g.ticket_summary);
      lines.push("");
      if (g.acceptance_criteria.length > 0) {
        lines.push("Acceptance Criteria:");
        g.acceptance_criteria.forEach((ac) => lines.push(`- ${ac}`));
        lines.push("");
      }
      if (g.ambiguities.length > 0) {
        lines.push("Open Questions / Ambiguities:");
        g.ambiguities.forEach((a) => lines.push(`- ${a}`));
        lines.push("");
      }
      if (g.dependencies.length > 0) {
        lines.push("Dependencies:");
        g.dependencies.forEach((d) => lines.push(`- ${d}`));
        lines.push("");
      }
      if (g.grooming_notes) {
        lines.push("Notes:");
        lines.push(g.grooming_notes);
      }

      await updateJiraIssue(selectedIssue.key, null, lines.join("\n").trim());
      setJiraUpdateStatus("saved");
    } catch (e) {
      setJiraUpdateError(String(e));
      setJiraUpdateStatus("error");
    }
  }

  // ── Individual stage runners (each called after user approves the previous) ──

  async function runImpactStage() {
    setCurrentStage("impact");
    setViewingStage("impact");
    try {
      const impactInput = prependSkill(ticketTextRef.current, skillsRef.current.patterns, "CODEBASE PATTERNS");
      const raw = await runImpactAnalysis(impactInput, JSON.stringify(groomingRef.current));
      const data = parseAgentJson<ImpactOutput>(raw);
      if (!data) throw new Error("Could not parse impact output");
      impactRef.current = data;
      setImpact(data);
      markComplete("impact");
      // ── CHECKPOINT ──
      setPendingApproval("impact");
    } catch (e) {
      setError("impact", String(e));
    }
  }

  async function runTriageStage() {
    setCurrentStage("triage");
    setViewingStage("triage");
    const contextText = compilePipelineContext(
      ticketTextRef.current, groomingRef.current, impactRef.current, skillsRef.current
    );
    setTriageSending(true);
    try {
      const initialMessage = "Please analyse this ticket and propose a concrete implementation approach. Ask any clarifying questions you need answered before we can finalise the plan.";
      const response = await runTriageTurn(
        contextText,
        JSON.stringify([{ role: "user", content: initialMessage }])
      );
      setTriageHistory([
        { role: "user" as const, content: initialMessage },
        { role: "assistant" as const, content: response },
      ]);
    } catch (e) {
      setError("triage", String(e));
    } finally {
      setTriageSending(false);
    }
  }

  async function sendTriageMessage() {
    if (!triageInput.trim()) return;
    const userMsg: TriageMessage = { role: "user", content: triageInput.trim() };
    const newHistory = [...triageHistory, userMsg];
    setTriageHistory(newHistory);
    setTriageInput("");
    setTriageSending(true);
    try {
      const contextText = compilePipelineContext(
        ticketTextRef.current, groomingRef.current, impactRef.current, skillsRef.current
      );
      const response = await runTriageTurn(contextText, JSON.stringify(newHistory));
      setTriageHistory([...newHistory, { role: "assistant", content: response }]);
    } catch (e) {
      setError("triage", String(e));
    } finally {
      setTriageSending(false);
    }
  }

  async function finalizePlan() {
    setTriaFinalizing(true);
    setCurrentStage("plan");
    try {
      const contextText = compilePipelineContext(
        ticketTextRef.current, groomingRef.current, impactRef.current, skillsRef.current
      );
      const raw = await finalizeImplementationPlan(contextText, JSON.stringify(triageHistory));
      const data = parseAgentJson<ImplementationPlan>(raw);
      if (!data) throw new Error("Could not parse plan output");
      planRef.current = data;
      setPlan(data);
      markComplete("triage");
      markComplete("plan");
      setViewingStage("plan");
      // ── CHECKPOINT: user reviews the plan before implementation begins ──
      setPendingApproval("plan");
    } catch (e) {
      setError("plan", String(e));
    } finally {
      setTriaFinalizing(false);
    }
  }

  async function runGuidanceStage() {
    const skills = skillsRef.current;
    const planJson = JSON.stringify(planRef.current);
    setCurrentStage("guidance");
    setViewingStage("guidance");
    try {
      const guidanceInput = prependSkill(
        prependSkill(ticketTextRef.current, skills.patterns, "CODEBASE PATTERNS"),
        skills.implementation, "IMPLEMENTATION STANDARDS"
      );
      const raw = await runImplementationGuidance(guidanceInput, planJson);
      const data = parseAgentJson<GuidanceOutput>(raw);
      if (!data) throw new Error("Could not parse guidance output");
      guidanceRef.current = data;
      setGuidance(data);
      markComplete("guidance");
      // ── CHECKPOINT ──
      setPendingApproval("guidance");
    } catch (e) {
      setError("guidance", String(e));
    }
  }

  async function runTestsStage() {
    const planJson = JSON.stringify(planRef.current);
    setCurrentStage("tests");
    setViewingStage("tests");
    try {
      const raw = await runTestSuggestions(planJson, JSON.stringify(guidanceRef.current));
      const data = parseAgentJson<TestOutput>(raw);
      if (!data) throw new Error("Could not parse test output");
      testsRef.current = data;
      setTests(data);
      markComplete("tests");
      // ── CHECKPOINT ──
      setPendingApproval("tests");
    } catch (e) {
      setError("tests", String(e));
    }
  }

  async function runReviewStage() {
    const skills = skillsRef.current;
    const planJson = JSON.stringify(planRef.current);
    setCurrentStage("review");
    setViewingStage("review");
    try {
      const reviewPlanJson = skills.review
        ? `=== REVIEW STANDARDS (follow these) ===\n${skills.review}\n\n${planJson}`
        : planJson;
      const raw = await runPlanReview(
        reviewPlanJson, JSON.stringify(guidanceRef.current), JSON.stringify(testsRef.current)
      );
      const data = parseAgentJson<PlanReviewOutput>(raw);
      if (!data) throw new Error("Could not parse review output");
      reviewRef.current = data;
      setReview(data);
      markComplete("review");
      // ── CHECKPOINT ──
      setPendingApproval("review");
    } catch (e) {
      setError("review", String(e));
    }
  }

  async function runPrStage() {
    const planJson = JSON.stringify(planRef.current);
    setCurrentStage("pr");
    setViewingStage("pr");
    try {
      const raw = await runPrDescriptionGen(
        ticketTextRef.current, planJson, JSON.stringify(reviewRef.current)
      );
      const data = parseAgentJson<PrDescriptionOutput>(raw);
      if (!data) throw new Error("Could not parse PR description output");
      setPrDescription(data);
      markComplete("pr");
      // ── CHECKPOINT ──
      setPendingApproval("pr");
    } catch (e) {
      setError("pr", String(e));
    }
  }

  async function runRetroStage() {
    const planJson = JSON.stringify(planRef.current);
    setCurrentStage("retro");
    setViewingStage("retro");
    try {
      const raw = await runRetrospectiveAgent(
        ticketTextRef.current, planJson, JSON.stringify(reviewRef.current)
      );
      const data = parseAgentJson<RetrospectiveOutput>(raw);
      if (!data) throw new Error("Could not parse retrospective output");
      setRetrospective(data);
      markComplete("retro");
      // ── CHECKPOINT ──
      setPendingApproval("retro");
    } catch (e) {
      setError("retro", String(e));
    }
  }

  // Dispatch from one approval gate to the next stage runner
  async function proceedFromStage(stage: Stage) {
    setPendingApproval(null);
    setProceeding(true);
    try {
      switch (stage) {
        case "grooming":   await runImpactStage(); break;
        case "impact":     await runTriageStage(); break;
        case "plan":       await runGuidanceStage(); break;
        case "guidance":   await runTestsStage(); break;
        case "tests":      await runReviewStage(); break;
        case "review":     await runPrStage(); break;
        case "pr":         await runRetroStage(); break;
        case "retro":      setCurrentStage("complete"); break;
      }
    } finally {
      setProceeding(false);
    }
  }

  // Follow-up chat at any stage's checkpoint (uses runTriageTurn with stage context)
  async function sendCheckpointMessage(stage: Stage) {
    const msg = checkpointInput.trim();
    if (!msg) return;
    setCheckpointInput("");

    const stageOutput =
      stage === "grooming" ? groomingRef.current :
      stage === "impact"   ? impactRef.current :
      stage === "plan"     ? planRef.current :
      stage === "guidance" ? guidanceRef.current :
      stage === "tests"    ? testsRef.current :
      stage === "review"   ? reviewRef.current :
      stage === "pr"       ? prDescription :
      stage === "retro"    ? retrospective : null;

    const context = [
      compilePipelineContext(ticketTextRef.current, groomingRef.current, impactRef.current, skillsRef.current),
      stageOutput ? `=== ${(STAGE_LABELS[stage as keyof typeof STAGE_LABELS] ?? stage).toUpperCase()} OUTPUT ===\n${JSON.stringify(stageOutput, null, 2)}` : "",
    ].filter(Boolean).join("\n\n");

    const prev = checkpointChats[stage] ?? [];
    const newHistory: TriageMessage[] = [...prev, { role: "user" as const, content: msg }];
    setCheckpointChats((c) => ({ ...c, [stage]: newHistory }));
    setCheckpointSending(true);
    try {
      const response = await runTriageTurn(context, JSON.stringify(newHistory));
      setCheckpointChats((c) => ({
        ...c,
        [stage]: [...(c[stage] ?? newHistory), { role: "assistant" as const, content: response }],
      }));
    } catch { /* silently drop — chat is non-critical */ }
    finally { setCheckpointSending(false); }
  }

  async function saveToKnowledgeBase(entries: RetroKbEntry[]) {
    const now = isoNow();
    for (const entry of entries) {
      await saveKnowledgeEntry({
        id: newId(),
        entryType: entry.type,
        title: entry.title,
        body: entry.body,
        tags: ["auto-generated", selectedIssue?.key ?? "unknown"],
        createdAt: now,
        updatedAt: now,
        linkedJiraKey: selectedIssue?.key ?? null,
        linkedPrId: null,
      });
    }
    setKbSaved(true);
  }

  // ── Stage content renderer ──────────────────────────────────────────────────

  function renderCheckpoint(stage: Stage) {
    // Grooming has its own inline conversation UI — skip the generic footer for it
    if (stage === "grooming") return null;
    // Only show the checkpoint footer if this is the current pending stage
    // (or a past stage — user can revisit and still chat)
    if (!completedStages.has(stage)) return null;
    const isPending = pendingApproval === stage;
    const isRetro = stage === "retro";
    return (
      <CheckpointFooter
        stage={stage}
        onProceed={() => isRetro ? proceedFromStage(stage) : proceedFromStage(stage)}
        proceeding={proceeding && pendingApproval === null && currentStage !== stage}
        hasBlockingIssues={stage === "review" && (review?.findings.some(f => f.severity === "blocking") ?? false)}
        chat={checkpointChats[stage] ?? []}
        input={isPending || viewingStage === stage ? checkpointInput : ""}
        onInputChange={(v) => setCheckpointInput(v)}
        onSend={() => sendCheckpointMessage(stage)}
        sending={checkpointSending && viewingStage === stage}
      />
    );
  }

  function renderStageContent(stage: Stage) {
    const err = errors[stage];
    if (err) {
      return (
        <div className="rounded-md border border-destructive/50 bg-destructive/10 p-4">
          <p className="text-sm font-medium text-destructive mb-1">Error in {STAGE_LABELS[stage as keyof typeof STAGE_LABELS]}</p>
          <pre className="text-xs text-muted-foreground whitespace-pre-wrap">{err}</pre>
        </div>
      );
    }

    if (stage === "grooming") {
      if (!grooming) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Running grooming analysis…</div>;

      // Two-column layout: grooming panel on the left, refine chat on the right.
      // Both columns are independently scrollable and fill the available height.
      // The parent container's max-w-2xl constraint is lifted for this stage (see render below).
      return (
        <div className="flex min-h-0 h-full">
          {/* ── Left: grooming analysis panel ── */}
          <div className="flex-1 min-w-0 overflow-y-auto space-y-3 pr-1">
            <GroomingPanel
            data={grooming}
            baseline={groomingBaseline}
            descriptionSections={selectedIssue?.descriptionSections}
            description={selectedIssue?.description}
            stepsToReproduce={selectedIssue?.stepsToReproduce}
            observedBehavior={selectedIssue?.observedBehavior}
            expectedBehavior={selectedIssue?.expectedBehavior}
          />
            {groomingBlockers.length > 0 && <BlockerBanner blockers={groomingBlockers} />}
          </div>

          {/* ── Drag handle ── */}
          {completedStages.has("grooming") && (
            <div
              onMouseDown={onDividerMouseDown}
              className="w-1.5 shrink-0 mx-2 rounded-full cursor-col-resize hover:bg-muted-foreground/30 active:bg-muted-foreground/50 transition-colors"
              title="Drag to resize"
            />
          )}

          {/* ── Right: refine chat panel ── */}
          {completedStages.has("grooming") && (
            <div
              className="shrink-0 flex flex-col min-h-0 border-l pl-5"
              style={{ width: chatPaneWidth }}
            >
              {/* Header */}
              <div className="shrink-0 pb-2 flex items-center justify-between">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                  Refine this ticket
                </p>
                {/* JIRA update button */}
                <div className="flex items-center gap-2">
                  {jiraUpdateStatus === "saved" && (
                    <span className="flex items-center gap-1 text-xs text-green-600">
                      <Check className="h-3 w-3" /> Saved
                    </span>
                  )}
                  {jiraUpdateStatus === "error" && (
                    <span className="text-xs text-destructive" title={jiraUpdateError}>Error</span>
                  )}
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-1.5 h-7 text-xs"
                    onClick={pushGroomingToJira}
                    disabled={jiraUpdateStatus === "saving" || groomingChat.length === 0}
                    title="Update the JIRA ticket description with the agreed grooming output"
                  >
                    {jiraUpdateStatus === "saving" ? (
                      <Loader2 className="h-3.5 w-3.5 animate-spin" />
                    ) : (
                      <ExternalLink className="h-3.5 w-3.5" />
                    )}
                    Update JIRA
                  </Button>
                </div>
              </div>

              <p className="text-xs text-muted-foreground shrink-0 pb-2">
                Suggest changes to the ticket. The panel updates live as we agree on changes.
              </p>

              {/* Chat history — scrollable, fills available height */}
              <div className="flex-1 min-h-0 overflow-y-auto space-y-2 pr-1 pb-2">
                {groomingChat.length === 0 && !groomingChatSending && (
                  <p className="text-xs text-muted-foreground italic text-center pt-4">
                    No messages yet. Start by suggesting a change below.
                  </p>
                )}
                {groomingChat.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                    <div className={`max-w-[90%] rounded-lg px-3 py-2 text-sm leading-relaxed ${
                      msg.role === "user" ? "bg-primary text-primary-foreground" : "bg-muted text-foreground"
                    }`}>
                      <p className="whitespace-pre-wrap">{
                        msg.role === "assistant"
                          ? msg.content.replace(/```json[\s\S]*?```/g, "").trim() || msg.content
                          : msg.content
                      }</p>
                    </div>
                  </div>
                ))}
                {groomingChatSending && (
                  <div className="flex justify-start">
                    <div className="bg-muted rounded-lg px-3 py-2 flex items-center gap-2 text-sm text-muted-foreground">
                      <Loader2 className="h-3.5 w-3.5 animate-spin" /> Updating…
                    </div>
                  </div>
                )}
              </div>

              {/* Input — pinned to bottom */}
              <div className="shrink-0 space-y-2 pt-2 border-t">
                <div className="flex gap-2">
                  <Textarea
                    value={groomingChatInput}
                    onChange={(e) => setGroomingChatInput(e.target.value)}
                    placeholder="Suggest changes or ask questions…"
                    className="min-h-[52px] resize-none text-sm"
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && (e.metaKey || e.ctrlKey) && groomingChatInput.trim()) {
                        e.preventDefault();
                        sendGroomingChatMessage();
                      }
                    }}
                    disabled={groomingChatSending || proceeding}
                  />
                  <Button
                    size="icon"
                    onClick={sendGroomingChatMessage}
                    disabled={!groomingChatInput.trim() || groomingChatSending || proceeding}
                    title="Send (⌘↵)"
                  >
                    <Send className="h-4 w-4" />
                  </Button>
                </div>
                <p className="text-xs text-muted-foreground">⌘↵ to send</p>

                {/* Proceed button */}
                <div className="flex items-center justify-between gap-2 border-t pt-2">
                  {groomingBlockers.some(b => b.severity === "blocking") && (
                    <p className="text-xs text-amber-600 dark:text-amber-400 flex items-center gap-1">
                      <AlertTriangle className="h-3 w-3 shrink-0" />
                      Blocking issues
                    </p>
                  )}
                  <Button
                    onClick={() => proceedFromStage("grooming")}
                    disabled={proceeding}
                    variant={groomingBlockers.some(b => b.severity === "blocking") ? "outline" : "default"}
                    size="sm"
                    className="gap-1.5 ml-auto text-xs"
                  >
                    {proceeding ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <ChevronRight className="h-3.5 w-3.5" />}
                    {groomingBlockers.some(b => b.severity === "blocking")
                      ? "Proceed anyway"
                      : "Proceed to Impact Analysis"}
                  </Button>
                </div>
              </div>
            </div>
          )}
        </div>
      );
    }
    if (stage === "impact") {
      if (!impact) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Running impact analysis…</div>;
      return (
        <>
          <ImpactPanel data={impact} />
          {renderCheckpoint(stage)}
        </>
      );
    }
    if (stage === "triage" || stage === "plan") {
      if (plan && completedStages.has("plan")) {
        return (
          <>
            <PlanPanel data={plan} />
            {renderCheckpoint("plan")}
          </>
        );
      }
      return (
        <TriageChat
          history={triageHistory}
          input={triageInput}
          onInputChange={setTriageInput}
          onSend={sendTriageMessage}
          onFinalize={finalizePlan}
          sending={triageSending}
          finalizing={triaFinalizing}
        />
      );
    }
    if (stage === "guidance") {
      if (!guidance) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Generating implementation guidance…</div>;
      return (
        <>
          <GuidancePanel data={guidance} />
          {renderCheckpoint(stage)}
        </>
      );
    }
    if (stage === "tests") {
      if (!tests) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Generating test suggestions…</div>;
      return (
        <>
          <TestsPanel data={tests} />
          {renderCheckpoint(stage)}
        </>
      );
    }
    if (stage === "review") {
      if (!review) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Reviewing the plan…</div>;
      return (
        <>
          <ReviewPanel data={review} />
          {renderCheckpoint(stage)}
        </>
      );
    }
    if (stage === "pr") {
      if (!prDescription) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Generating PR description…</div>;
      return (
        <>
          <PrPanel data={prDescription} />
          {renderCheckpoint(stage)}
        </>
      );
    }
    if (stage === "retro") {
      if (!retrospective) return <div className="flex items-center gap-2 text-sm text-muted-foreground"><Loader2 className="h-4 w-4 animate-spin" /> Running retrospective…</div>;
      return (
        <>
          <RetroPanel data={retrospective} onSaveToKb={saveToKnowledgeBase} kbSaved={kbSaved} />
          {currentStage !== "complete" && renderCheckpoint(stage)}
        </>
      );
    }
    return null;
  }

  // ── Render ──────────────────────────────────────────────────────────────────

  return (
    <div className="flex h-dvh min-h-0 flex-col overflow-hidden">
      {/* Header */}
      <header className={cn(APP_HEADER_BAR, "z-20 shrink-0")}>
        <div className={cn(APP_HEADER_ROW_PANEL, "relative")}>
          {/* Back + title — left (same slot as other panels) */}
          <div className="relative z-10 flex min-w-0 shrink-0 items-center gap-2">
            <Button
              variant="ghost"
              size="icon"
              className="shrink-0"
              onClick={currentStage === "select" ? onBack : () => { setSelectedIssue(null); setCurrentStage("select"); }}
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <span className={cn(APP_HEADER_TITLE, "shrink-0")}>Implement a Ticket</span>
          </div>

          <div className="min-w-0 flex-1" aria-hidden />

          <HeaderSettingsButton className="relative z-30 shrink-0" />

          {/* Meridian mark centred in header; morphs to pipeline ring when a ticket run is active */}
          <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
            <div
              className={cn(
                "absolute bottom-0 left-1/2 flex h-14 min-h-0 -translate-x-1/2 justify-center overflow-hidden",
                currentStage !== "select" ? "w-1/2 max-w-md" : "w-auto max-w-md",
                meridianHeaderVisible ? "opacity-100" : "opacity-0"
              )}
              style={{
                transition:
                  "width 700ms ease-in-out, max-width 700ms ease-in-out, opacity 1000ms ease-out",
              }}
            >
              <PipelineProgress
                activeStep={currentStage === "select" ? undefined : stageToStep(viewingStage)}
                logoAlign="center"
                className={`block h-full min-h-0 opacity-100 transition-opacity duration-300 ease-out ${
                  currentStage === "select" ? "w-auto max-h-14" : "w-full"
                }`}
              />
            </div>
          </div>
        </div>
      </header>

      {/* Ticket info bar — shown once a ticket is selected */}
      {selectedIssue && (
        <div className="shrink-0 px-4 py-1.5 border-b bg-muted/20 flex items-center gap-2 min-w-0">
          <JiraTicketLink ticketKey={selectedIssue.key} url={selectedIssue.url} />
          <span className="text-xs text-muted-foreground truncate flex-1">— {selectedIssue.summary}</span>
          <Button variant="outline" size="sm" className="shrink-0" onClick={() => selectedIssue.url && openUrl(selectedIssue.url)}>
            <ExternalLink className="h-3.5 w-3.5 mr-1" /> JIRA
          </Button>
        </div>
      )}

      {/* Credential warnings */}
      {(!jiraAvailable || !claudeAvailable) && (
        <div className="shrink-0 px-4 py-2 bg-amber-50 dark:bg-amber-950/30 border-b border-amber-200 dark:border-amber-900 text-xs text-amber-800 dark:text-amber-200">
          {!jiraAvailable && "JIRA credentials not configured. "}
          {!claudeAvailable && "No AI provider configured — add an Anthropic key, Gemini key, or local LLM URL in Settings."}
        </div>
      )}

      {/* Body — full-width card; fills viewport below chrome so only the stage panel scrolls */}
      <div className={`flex min-h-0 flex-1 flex-col overflow-hidden ${currentStage === "select" ? "p-4" : "px-2 py-2"}`}>
        <div className={`flex min-h-0 w-full flex-1 flex-col overflow-hidden rounded-xl bg-background/60 ${currentStage === "select" ? "mx-auto max-w-3xl" : ""}`}>
          {currentStage === "select" ? (
            <div className="min-h-0 flex-1 overflow-y-auto p-6">
              <TicketSelector sprintIssues={sprintIssues} loading={loadingIssues} onSelect={startPipeline} />
            </div>
          ) : (
            <div className="flex min-h-0 flex-1 overflow-hidden">
              <PipelineSidebar
                currentStage={currentStage}
                completedStages={completedStages}
                activeStage={viewingStage}
                pendingApproval={pendingApproval}
                onClickStage={setViewingStage}
              />

              <div className="flex min-h-0 min-w-0 flex-1 flex-col">
                <div className="shrink-0 px-5 pt-5">
                  <div className="mb-2 flex items-center justify-between">
                    <div>
                      <h2 className="text-base font-semibold">
                        {viewingStage === "triage" && !completedStages.has("plan")
                          ? "Triage"
                          : viewingStage === "triage" || viewingStage === "plan"
                            ? "Implementation Plan"
                            : STAGE_LABELS[viewingStage as keyof typeof STAGE_LABELS]}
                      </h2>
                      {currentStage === "complete" && viewingStage === "retro" && (
                        <p className="mt-0.5 flex items-center gap-1 text-xs font-medium text-green-600">
                          <CheckCircle2 className="h-3 w-3" /> Pipeline complete
                        </p>
                      )}
                    </div>
                    {completedStages.has(viewingStage as Stage) &&
                      viewingStage !== "triage" &&
                      viewingStage !== "plan" && (
                        <CopyButton
                          text={
                            JSON.stringify(
                              viewingStage === "grooming"
                                ? grooming
                                : viewingStage === "impact"
                                  ? impact
                                  : viewingStage === "guidance"
                                    ? guidance
                                    : viewingStage === "tests"
                                      ? tests
                                      : viewingStage === "review"
                                        ? review
                                        : null,
                              null,
                              2
                            ) ?? ""
                          }
                          label="Copy JSON"
                        />
                      )}
                  </div>
                </div>
                <div className={`min-h-0 flex-1 ${viewingStage === "grooming" && grooming ? "overflow-hidden px-5 pb-5 flex flex-col" : "overflow-y-auto px-5 pb-5"}`}>
                  <div className={viewingStage === "grooming" && grooming ? "flex-1 min-h-0" : ""}>{renderStageContent(viewingStage)}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

use std::path::{Path, PathBuf};
use std::process::Command;
use serde::Serialize;

use super::credentials::get_credential;

// ── Helpers ───────────────────────────────────────────────────────────────────

fn worktree_path() -> Result<PathBuf, String> {
    let raw = get_credential("repo_worktree_path")
        .ok_or("Codebase worktree path not configured. Set it in Settings → Configuration.")?;
    let path = PathBuf::from(raw.trim());
    if !path.exists() {
        return Err(format!(
            "Worktree path '{}' does not exist. Check Settings → Configuration.",
            path.display()
        ));
    }
    Ok(path)
}

fn base_branch() -> String {
    get_credential("repo_base_branch")
        .unwrap_or_else(|| "develop".to_string())
}

/// Returns the PR review–specific worktree path if configured, otherwise falls
/// back to the main worktree path. Returns an error only if neither is set.
fn pr_review_worktree_path() -> Result<PathBuf, String> {
    let raw = get_credential("pr_review_worktree_path")
        .or_else(|| get_credential("repo_worktree_path"))
        .ok_or("No worktree path configured. Set one in Settings → Configuration.")?;
    let path = PathBuf::from(raw.trim());
    if !path.exists() {
        return Err(format!(
            "Worktree path '{}' does not exist. Check Settings → Configuration.",
            path.display()
        ));
    }
    Ok(path)
}

/// Run a git command inside the worktree, returning stdout as a String.
fn git(dir: &Path, args: &[&str]) -> Result<String, String> {
    let out = Command::new("git")
        .arg("-C")
        .arg(dir)
        .args(args)
        .output()
        .map_err(|e| format!("git error: {e}"))?;

    if !out.status.success() {
        let stderr = String::from_utf8_lossy(&out.stderr);
        return Err(format!("git {} failed: {}", args.join(" "), stderr.trim()));
    }
    Ok(String::from_utf8_lossy(&out.stdout).to_string())
}

/// Sandbox a user-supplied relative path to the worktree root.
/// Returns an absolute path and an error if the resolved path would escape the root.
fn sandboxed(root: &Path, rel: &str) -> Result<PathBuf, String> {
    // Strip leading slashes/dots to prevent absolute-path injection
    let rel = rel.trim_start_matches('/').trim_start_matches("./");
    let full = root.join(rel);
    // Canonicalise both so symlinks can't escape
    let canon_full = full.canonicalize()
        .map_err(|_| format!("Path not found: {rel}"))?;
    let canon_root = root.canonicalize()
        .map_err(|_| "Could not canonicalise worktree root".to_string())?;
    if !canon_full.starts_with(&canon_root) {
        return Err(format!("Path '{rel}' would escape the worktree root — not allowed."));
    }
    Ok(canon_full)
}

// ── Worktree management ───────────────────────────────────────────────────────

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
pub struct WorktreeInfo {
    pub path: String,
    pub branch: String,
    pub head_commit: String,
    pub head_message: String,
}

/// Validate that the configured path is a git worktree, returning basic metadata.
#[tauri::command]
pub async fn validate_worktree() -> Result<WorktreeInfo, String> {
    let path = worktree_path()?;

    // Confirm it's a git repository (worktree or main checkout)
    git(&path, &["rev-parse", "--git-dir"])?;

    let branch = git(&path, &["rev-parse", "--abbrev-ref", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_commit = git(&path, &["rev-parse", "--short", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_message = git(&path, &["log", "-1", "--format=%s"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| String::new());

    Ok(WorktreeInfo {
        path: path.to_string_lossy().to_string(),
        branch,
        head_commit,
        head_message,
    })
}

/// Fetch from origin and reset the worktree to the configured base branch.
/// Returns the new HEAD commit hash.
#[tauri::command]
pub async fn sync_worktree() -> Result<WorktreeInfo, String> {
    let path = worktree_path()?;
    let branch = base_branch();

    // Fetch
    git(&path, &["fetch", "origin"])
        .map_err(|e| format!("git fetch failed: {e}"))?;

    // Reset hard to origin/<branch>
    let remote_ref = format!("origin/{branch}");
    git(&path, &["reset", "--hard", &remote_ref])
        .map_err(|e| format!("git reset to {remote_ref} failed: {e}"))?;

    let head_commit = git(&path, &["rev-parse", "--short", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_message = git(&path, &["log", "-1", "--format=%s"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| String::new());

    Ok(WorktreeInfo {
        path: path.to_string_lossy().to_string(),
        branch,
        head_commit,
        head_message,
    })
}

// ── File access (read-only, sandboxed) ───────────────────────────────────────

/// Search files by glob pattern. Returns relative paths from the worktree root.
/// Pattern is relative to the root (e.g. "src/**/*.ts").
/// Hard-capped at 500 results to avoid flooding the context window.
#[tauri::command]
pub async fn glob_repo_files(pattern: String) -> Result<Vec<String>, String> {
    let root = worktree_path()?;

    // Use `git ls-files` with fnmatch-style patterns — respects .gitignore automatically.
    // Fall back to a plain find for patterns that don't match gitignore-aware ls-files.
    let output = git(&root, &["ls-files", "--cached", "--others", "--exclude-standard", &pattern])
        .unwrap_or_default();

    let mut results: Vec<String> = output
        .lines()
        .filter(|l| !l.is_empty())
        .take(500)
        .map(str::to_string)
        .collect();

    // git ls-files doesn't always do recursive glob; if we got nothing, try find
    if results.is_empty() {
        // Strip leading src/ or similar for the glob portion
        let out = Command::new("find")
            .arg(&root)
            .arg("-type")
            .arg("f")
            .arg("-not")
            .arg("-path")
            .arg("*/.git/*")
            .output()
            .map_err(|e| format!("find error: {e}"))?;
        let all = String::from_utf8_lossy(&out.stdout);
        let pat = glob::Pattern::new(&pattern)
            .map_err(|e| format!("Invalid glob pattern: {e}"))?;
        results = all
            .lines()
            .filter_map(|line| {
                let p = Path::new(line);
                let rel = p.strip_prefix(&root).ok()?;
                let rel_str = rel.to_string_lossy();
                if pat.matches(&rel_str) {
                    Some(rel_str.to_string())
                } else {
                    None
                }
            })
            .take(500)
            .collect();
    }

    Ok(results)
}

/// Search file contents with a regex pattern using `git grep`.
/// `path` is an optional subdirectory to restrict the search to.
/// Returns at most 200 matches as "path:line:content" strings.
#[tauri::command]
pub async fn grep_repo_files(pattern: String, path: Option<String>) -> Result<Vec<String>, String> {
    let root = worktree_path()?;

    let mut args = vec![
        "grep",
        "-n",           // line numbers
        "--heading",    // group by file
        "-E",           // extended regex
        "--max-count=50", // max 50 matches per file
        &pattern,
    ];
    let path_owned;
    if let Some(ref p) = path {
        path_owned = p.clone();
        args.push("--");
        args.push(&path_owned);
    }

    let output = git(&root, &args).unwrap_or_default();
    let lines: Vec<String> = output
        .lines()
        .take(200)
        .map(str::to_string)
        .collect();

    Ok(lines)
}

/// Read a single file from the worktree.
/// `path` is relative to the worktree root (e.g. "src/reports/index.ts").
/// Hard-capped at 500 KB to prevent enormous files from flooding the context window.
#[tauri::command]
pub async fn read_repo_file(path: String) -> Result<String, String> {
    let root = worktree_path()?;
    let full = sandboxed(&root, &path)?;

    let content = std::fs::read_to_string(&full)
        .map_err(|e| format!("Could not read '{}': {e}", path))?;

    // Cap at ~500 KB
    const MAX_BYTES: usize = 512 * 1024;
    if content.len() > MAX_BYTES {
        let truncated = &content[..MAX_BYTES];
        return Ok(format!(
            "{truncated}\n\n[… file truncated at 500 KB — {} bytes omitted …]",
            content.len() - MAX_BYTES
        ));
    }

    Ok(content)
}

/// Get the git diff of the worktree against the configured base branch.
/// Used by the PR Description agent to summarise what changed.
#[tauri::command]
pub async fn get_repo_diff() -> Result<String, String> {
    let root = worktree_path()?;
    let branch = base_branch();
    let remote_ref = format!("origin/{branch}");

    // diff against the merge-base so we only see changes since branching
    let merge_base = git(&root, &["merge-base", "HEAD", &remote_ref])
        .map(|s| s.trim().to_string())
        .unwrap_or(remote_ref.clone());

    let diff = git(&root, &["diff", &merge_base, "HEAD"])?;

    // Cap at 1 MB
    const MAX_BYTES: usize = 1024 * 1024;
    if diff.len() > MAX_BYTES {
        return Ok(format!(
            "{}\n\n[… diff truncated at 1 MB …]",
            &diff[..MAX_BYTES]
        ));
    }

    Ok(diff)
}

/// Run `git log` on the worktree against the base branch.
/// Returns the last N commits as a plain-text log.
#[tauri::command]
pub async fn get_repo_log(max_commits: u32) -> Result<String, String> {
    let root = worktree_path()?;
    let n = max_commits.min(100).to_string();
    let log = git(
        &root,
        &[
            "log",
            &format!("-{n}"),
            "--oneline",
            "--decorate",
            "--no-merges",
        ],
    )?;
    Ok(log)
}

// ── Shared branch-checkout logic ──────────────────────────────────────────────

/// Check out `branch` inside `path`, updating it to `origin/<branch>`.
///
/// Strategy (avoids the "branch already exists" error):
/// 1. `git fetch origin <branch>` — ensure the remote ref is fresh.
/// 2. Check whether a local branch named `<branch>` already exists with
///    `git branch --list <branch>`.
/// 3a. Branch exists locally  → `git checkout <branch>` then
///     `git reset --hard origin/<branch>` to fast-forward it.
/// 3b. Branch does not exist  → `git checkout -b <branch> --track origin/<branch>`.
///
/// Using `--list` instead of relying on checkout exit codes means we never
/// accidentally attempt `-b` on a branch that already exists (which produces
/// `fatal: a branch named '…' already exists`).
fn checkout_branch_in(path: &Path, branch: &str) -> Result<WorktreeInfo, String> {
    let remote_ref = format!("origin/{branch}");

    // 1. Fetch
    git(path, &["fetch", "origin", branch])
        .map_err(|e| format!("git fetch failed: {e}"))?;

    // 2. Does a local branch with this exact name already exist?
    let list_out = git(path, &["branch", "--list", branch]).unwrap_or_default();
    let exists_locally = !list_out.trim().is_empty();

    if exists_locally {
        // 3a. Already exists — check it out then hard-reset to the remote tip
        git(path, &["checkout", branch])
            .map_err(|e| format!("git checkout {branch} failed: {e}"))?;
        git(path, &["reset", "--hard", &remote_ref])
            .map_err(|e| format!("git reset to {remote_ref} failed: {e}"))?;
    } else {
        // 3b. New locally — create it tracking the remote
        git(path, &["checkout", "-b", branch, "--track", &remote_ref])
            .map_err(|e| format!("git checkout -b {branch} failed: {e}"))?;
    }

    let head_commit = git(path, &["rev-parse", "--short", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_message = git(path, &["log", "-1", "--format=%s"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| String::new());

    Ok(WorktreeInfo {
        path: path.to_string_lossy().to_string(),
        branch: branch.to_string(),
        head_commit,
        head_message,
    })
}

/// Check out a specific branch in the implementation worktree.
/// Returns the HEAD info after checkout.
#[tauri::command]
pub async fn checkout_worktree_branch(branch: String) -> Result<WorktreeInfo, String> {
    let path = worktree_path()?;
    let branch = branch.trim().to_string();
    if branch.is_empty() {
        return Err("Branch name cannot be empty.".to_string());
    }
    checkout_branch_in(&path, &branch)
}

/// Run `git log` on a specific file to get its history.
/// Used by Impact Analysis to understand why code was written the way it was.
#[tauri::command]
pub async fn get_file_history(path: String, max_commits: u32) -> Result<String, String> {
    let root = worktree_path()?;
    let _ = sandboxed(&root, &path)?;
    let n = max_commits.min(20).to_string();
    let log = git(
        &root,
        &[
            "log",
            &format!("-{n}"),
            "--oneline",
            "--follow",
            "--",
            &path,
        ],
    )?;
    Ok(log)
}

/// Validate that the configured PR review worktree path is a valid git repository.
/// Falls back to the main worktree path if no dedicated PR review path is configured.
#[tauri::command]
pub async fn validate_pr_review_worktree() -> Result<WorktreeInfo, String> {
    let path = pr_review_worktree_path()?;

    git(&path, &["rev-parse", "--git-dir"])?;

    let branch = git(&path, &["rev-parse", "--abbrev-ref", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_commit = git(&path, &["rev-parse", "--short", "HEAD"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let head_message = git(&path, &["log", "-1", "--format=%s"])
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|_| String::new());

    Ok(WorktreeInfo {
        path: path.to_string_lossy().to_string(),
        branch,
        head_commit,
        head_message,
    })
}

/// Check out a specific branch in the PR review worktree.
/// Uses `pr_review_worktree_path` if configured, otherwise falls back to
/// `repo_worktree_path`.
#[tauri::command]
pub async fn checkout_pr_review_branch(branch: String) -> Result<WorktreeInfo, String> {
    let path = pr_review_worktree_path()?;
    let branch = branch.trim().to_string();
    if branch.is_empty() {
        return Err("Branch name cannot be empty.".to_string());
    }
    checkout_branch_in(&path, &branch)
}

/// Open a terminal window in the PR review worktree directory and run the
/// supplied command. The terminal application is read from the
/// `pr_review_terminal` credential (defaults to "iTerm2").
/// Supported values: "iTerm2", "Terminal", or any other app name that
/// supports the standard macOS Terminal AppleScript dictionary.
#[tauri::command]
pub async fn run_in_terminal(command: String) -> Result<(), String> {
    let path = pr_review_worktree_path()?;
    let path_str = path.to_string_lossy();

    let terminal = get_credential("pr_review_terminal")
        .unwrap_or_else(|| "iTerm2".to_string());
    let terminal = terminal.trim().to_string();

    let script = if terminal.to_lowercase() == "iterm2" || terminal == "iTerm2" {
        // iTerm2 has its own richer AppleScript dictionary.
        format!(
            r#"tell application "iTerm2"
    activate
    set newWindow to (create window with default profile)
    tell current session of newWindow
        write text "cd {path_str} && {command}"
    end tell
end tell"#
        )
    } else {
        // macOS Terminal.app and any other terminal that follows the standard
        // "do script" AppleScript convention.
        format!(
            r#"tell application "{terminal}"
    activate
    do script "cd {path_str} && {command}"
end tell"#
        )
    };

    let out = Command::new("osascript")
        .arg("-e")
        .arg(&script)
        .output()
        .map_err(|e| format!("Failed to launch {terminal}: {e}"))?;

    if !out.status.success() {
        let stderr = String::from_utf8_lossy(&out.stderr);
        return Err(format!("{terminal} launch failed: {stderr}"));
    }

    Ok(())
}

